const html = $input.first().json.data || '';
const url = $input.first().json.query?.url || '';

// Try structured data first
let title = '', company = '', description = '', location = '';

// JSON-LD
const jsonLdMatch = html.match(/<script type="application\/ld\+json">(.*?)<\/script>/gs);
if (jsonLdMatch) {
  for (const m of jsonLdMatch) {
    try {
      const d = JSON.parse(m.replace(/<\/?script[^>]*>/g, ''));
      if (d['@type'] === 'JobPosting') {
        title = d.title || '';
        company = d.hiringOrganization?.name || '';
        description = d.description || '';
        location = d.jobLocation?.address?.addressLocality || '';
      }
    } catch (e) {}
  }
}

// Greenhouse API detection
if (url.includes('boards.greenhouse.io')) {
  const ghMatch = url.match(/greenhouse\.io\/([^/]+)\/jobs\/(\d+)/);
  if (ghMatch) {
    try {
      // Will be fetched in next node if detected
      return [{ json: { ats: 'greenhouse', slug: ghMatch[1], jobId: ghMatch[2], url } }];
    } catch (e) {}
  }
}

// Lever API detection
if (url.includes('jobs.lever.co')) {
  const lvMatch = url.match(/lever\.co\/([^/]+)\/([a-f0-9-]+)/);
  if (lvMatch) {
    return [{ json: { ats: 'lever', slug: lvMatch[1], jobId: lvMatch[2], url } }];
  }
}

// Fallback: extract text from common selectors
if (!description) {
  const selectors = ['job-description', 'job-details', 'posting-requirements', 'content-payload'];
  for (const sel of selectors) {
    const regex = new RegExp(`class="[^"]*${sel}[^"]*"[^>]*>([\\s\\S]*?)<\/div>`, 'i');
    const match = html.match(regex);
    if (match) {
      description = match[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
      break;
    }
  }
}

// Meta tags fallback
if (!title) {
  const titleMatch = html.match(/<title>([^<]+)<\/title>/);
  title = titleMatch ? titleMatch[1].trim() : '';
}

return [{ json: { title, company, location, description: description.slice(0, 5000), url, source: 'scraper' } }];
